# Updated solver with the even-width swap rule for multi-color arms

def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(grid[0, 0])

    # Find color 3 cells
    pos3 = np.argwhere(grid == 3)
    if len(pos3) == 0:
        return grid.tolist()

    # Find connected components of color 3
    visited = set()
    components = []
    for r, c in pos3:
        r, c = int(r), int(c)
        if (r, c) in visited:
            continue
        queue = [(r, c)]
        visited.add((r, c))
        component = [(r, c)]
        while queue:
            cr, cc = queue.pop(0)
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = cr+dr, cc+dc
                if 0 <= nr < H and 0 <= nc < W and (nr, nc) not in visited and int(grid[nr, nc]) == 3:
                    visited.add((nr, nc))
                    queue.append((nr, nc))
                    component.append((nr, nc))
        components.append(component)

    # Largest component = main rectangle
    main_comp = max(components, key=len)
    rs = [r for r, c in main_comp]
    cs = [c for r, c in main_comp]
    r_min, r_max = min(rs), max(rs)
    c_min, c_max = min(cs), max(cs)

    # Interior
    ir1, ir2 = r_min + 1, r_max - 1
    ic1, ic2 = c_min + 1, c_max - 1

    # Interior fill color
    fill_color = int(grid[ir1, ic1])

    # Create output
    h = ir2 - ir1 + 1
    w = ic2 - ic1 + 1
    result = [[fill_color] * w for _ in range(h)]

    # Find arm colors (non-bg, non-3, non-fill)
    all_colors = set(int(x) for x in np.unique(grid)) - {bg, 3}
    if fill_color != bg:
        all_colors -= {fill_color}

    # Remove colors that only appear in non-main-component color-3 rects
    # (small decorative rects in the test)
    main_cells = set((r, c) for r, c in main_comp)

    # Group colors by bounding box
    color_bboxes = {}
    for color in all_colors:
        pos = np.argwhere(grid == color)
        bbox = (int(pos[:,0].min()), int(pos[:,1].min()), int(pos[:,0].max()), int(pos[:,1].max()))
        color_bboxes[color] = bbox

    bbox_to_colors = {}
    for color, bbox in color_bboxes.items():
        if bbox not in bbox_to_colors:
            bbox_to_colors[bbox] = []
        bbox_to_colors[bbox].append(color)

    for bbox, colors in bbox_to_colors.items():
        ar1, ac1, ar2, ac2 = bbox
        arm_width = ac2 - ac1 + 1

        if len(colors) == 1:
            color = colors[0]
            # Draw border cells in interior
            for c in range(ac1, ac2 + 1):
                for r in [ar1, ar2]:
                    if ir1 <= r <= ir2 and ic1 <= c <= ic2:
                        result[r - ir1][c - ic1] = color
            for r in range(ar1, ar2 + 1):
                for c in [ac1, ac2]:
                    if ir1 <= r <= ir2 and ic1 <= c <= ic2:
                        result[r - ir1][c - ic1] = color
        elif len(colors) == 2:
            # Multi-color arm
            color_at_even = None
            color_at_odd = None
            for color in colors:
                for r, c in np.argwhere(grid == color):
                    r, c = int(r), int(c)
                    parity = (r + c) % 2
                    if parity == 0:
                        color_at_even = color
                    else:
                        color_at_odd = color
                    if color_at_even is not None and color_at_odd is not None:
                        break
                if color_at_even is not None and color_at_odd is not None:
                    break

            # If arm width is even, swap colors for interior cells
            if arm_width % 2 == 0:
                color_at_even, color_at_odd = color_at_odd, color_at_even

            # Draw border cells
            for c in range(ac1, ac2 + 1):
                for r in [ar1, ar2]:
                    if ir1 <= r <= ir2 and ic1 <= c <= ic2:
                        parity = (r + c) % 2
                        clr = color_at_even if parity == 0 else color_at_odd
                        result[r - ir1][c - ic1] = clr
            for r in range(ar1, ar2 + 1):
                for c in [ac1, ac2]:
                    if ir1 <= r <= ir2 and ic1 <= c <= ic2:
                        parity = (r + c) % 2
                        clr = color_at_even if parity == 0 else color_at_odd
                        result[r - ir1][c - ic1] = clr

    return result

# Test on all training examples
for i, s in enumerate(train_samples):
    pred = solve(s['input'])
    expected = s['output']
    match = pred == expected
    print(f"Example {i}: {'✓' if match else '✗'}")
    if not match:
        for r in range(len(pred)):
            if pred[r] != expected[r]:
                print(f"  Row {r}: pred={pred[r]} exp={expected[r]}")

# Show test output
print("\nTest output:")
test_out = solve(test_samples[0]['input'])
for row in test_out:
    print(row)

